create extension if not exists "pgcrypto";
create type public.member_role as enum ('owner','admin','editor');
create type public.subscription_state as enum ('trialing','active','past_due','canceled');
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade, full_name text, avatar_url text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.restaurants (id uuid primary key default gen_random_uuid(), owner_id uuid not null references auth.users(id), name text not null, slug text not null unique check(slug ~ '^[a-z0-9]+(?:-[a-z0-9]+)*$'), description text, logo_url text, cover_url text, phone text, email text, address text, instagram_url text, website_url text, primary_color text not null default '#6d5dfc', secondary_color text not null default '#e879f9', currency text not null default 'EUR', locale text not null default 'es-ES', timezone text not null default 'Europe/Madrid', is_published boolean not null default false, plan text not null default 'carta', subscription_status public.subscription_state not null default 'trialing', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.restaurant_members (id uuid primary key default gen_random_uuid(), restaurant_id uuid not null references public.restaurants(id) on delete cascade, user_id uuid not null references auth.users(id) on delete cascade, role public.member_role not null default 'editor', created_at timestamptz not null default now(), unique(restaurant_id,user_id));
create table public.categories (id uuid primary key default gen_random_uuid(), restaurant_id uuid not null references public.restaurants(id) on delete cascade, name text not null, slug text not null, sort_order int not null default 0, is_active boolean not null default true, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(restaurant_id,slug));
create table public.products (id uuid primary key default gen_random_uuid(), restaurant_id uuid not null references public.restaurants(id) on delete cascade, category_id uuid not null references public.categories(id) on delete restrict, name text not null, description text, price_cents int not null check(price_cents>=0), video_url text, video_path text, image_url text, image_path text, is_available boolean not null default true, is_featured boolean not null default false, sort_order int not null default 0, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.subscriptions (id uuid primary key default gen_random_uuid(), restaurant_id uuid not null unique references public.restaurants(id) on delete cascade, provider text not null default 'stripe', provider_customer_id text, provider_subscription_id text, plan text not null default 'carta', status public.subscription_state not null default 'trialing', current_period_end timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create index restaurants_slug_idx on public.restaurants(slug); create index products_restaurant_idx on public.products(restaurant_id); create index categories_restaurant_idx on public.categories(restaurant_id); create index members_user_idx on public.restaurant_members(user_id); create index members_restaurant_idx on public.restaurant_members(restaurant_id);
create or replace function public.set_updated_at() returns trigger language plpgsql as $$begin new.updated_at=now();return new;end$$;
create trigger profiles_updated before update on public.profiles for each row execute function public.set_updated_at(); create trigger restaurants_updated before update on public.restaurants for each row execute function public.set_updated_at(); create trigger categories_updated before update on public.categories for each row execute function public.set_updated_at(); create trigger products_updated before update on public.products for each row execute function public.set_updated_at(); create trigger subscriptions_updated before update on public.subscriptions for each row execute function public.set_updated_at();
create or replace function public.is_member(target uuid) returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from restaurant_members where restaurant_id=target and user_id=auth.uid())$$;
create or replace function public.can_edit(target uuid) returns boolean language sql stable security definer set search_path=public as $$select exists(select 1 from restaurant_members where restaurant_id=target and user_id=auth.uid() and role in ('owner','admin','editor'))$$;
alter table public.profiles enable row level security; alter table public.restaurants enable row level security; alter table public.restaurant_members enable row level security; alter table public.categories enable row level security; alter table public.products enable row level security; alter table public.subscriptions enable row level security;
create policy "profiles own" on public.profiles for all using(id=auth.uid()) with check(id=auth.uid());
create policy "public published restaurants" on public.restaurants for select using(is_published or public.is_member(id)); create policy "owners create restaurants" on public.restaurants for insert with check(owner_id=auth.uid()); create policy "members update restaurants" on public.restaurants for update using(public.can_edit(id));
create policy "members read membership" on public.restaurant_members for select using(user_id=auth.uid()); create policy "owner add members" on public.restaurant_members for insert with check(public.is_member(restaurant_id) or user_id=auth.uid());
create policy "public active categories" on public.categories for select using(is_active or public.is_member(restaurant_id)); create policy "members manage categories" on public.categories for all using(public.can_edit(restaurant_id)) with check(public.can_edit(restaurant_id));
create policy "public available products" on public.products for select using(is_available or public.is_member(restaurant_id)); create policy "members manage products" on public.products for all using(public.can_edit(restaurant_id)) with check(public.can_edit(restaurant_id));
create policy "members subscriptions" on public.subscriptions for select using(public.is_member(restaurant_id));
insert into storage.buckets(id,name,public) values ('restaurant-media','restaurant-media',true) on conflict do nothing;
create policy "public media read" on storage.objects for select using(bucket_id='restaurant-media'); create policy "member media insert" on storage.objects for insert with check(bucket_id='restaurant-media' and public.can_edit((storage.foldername(name))[2]::uuid)); create policy "member media update" on storage.objects for update using(bucket_id='restaurant-media' and public.can_edit((storage.foldername(name))[2]::uuid)); create policy "member media delete" on storage.objects for delete using(bucket_id='restaurant-media' and public.can_edit((storage.foldername(name))[2]::uuid));
